import{_ as o,o as a,c as r,a2 as e}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"钟表馆（奉先殿）","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/zhongbiao-guan.md","filePath":"landmarks/forbidden-city/zhongbiao-guan.md","lastUpdated":1784720050000}'),n={name:"landmarks/forbidden-city/zhongbiao-guan.md"};function l(s,t,i,g,d,u){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="钟表馆-奉先殿" tabindex="-1">钟表馆（奉先殿） <a class="header-anchor" href="#钟表馆-奉先殿" aria-label="Permalink to &quot;钟表馆（奉先殿）&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1752140313622-dc6d8eb11197?w=1200&amp;q=80" alt="钟表馆"></p><blockquote><p>齿轮咬合之间，机械奏响乐声，玩偶提笔写字。这里是18至20世纪钟表制造的巅峰陈列，也是东西方技艺在紫禁城的一次盛大相遇。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>钟表馆位于故宫东侧的<strong>奉先殿</strong>，是故宫博物院的钟表专题展馆。奉先殿是明清两代皇帝祭祀祖先的家庙——&quot;奉先&quot;即&quot;敬奉先祖&quot;之意，殿内曾供奉列朝帝后神牌，是紫禁城内等级最高的祭祀建筑之一。如今，这座肃穆的祖庙成了时间机器的陈列厅，庄严与精巧在此奇妙地交汇。</p><p>馆藏中外钟表<strong>200余件</strong>，涵盖<strong>英国、法国、瑞士、日本</strong>及<strong>清宫造办处</strong>自制钟表，年代横跨18世纪至20世纪初。这些钟表绝大多数是清代宫廷旧藏——部分是西洋各国使节进贡的礼品，部分是广州、苏州工匠仿制的&quot;广钟&quot;&quot;苏钟&quot;，还有相当数量是清宫造办处做钟处直接承制的御用钟。它们不只是计时工具，更是集机械、音乐、雕塑、珐琅、珠宝于一体的综合艺术品，代表了工业革命前后世界钟表制造的最高水平。</p><p><strong>需另购票10元</strong>（凭故宫大门票在奉先殿入口购买）。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>位置</strong></td><td style="text-align:left;">故宫东侧奉先殿（东六宫以南）</td></tr><tr><td style="text-align:left;"><strong>门票</strong></td><td style="text-align:left;">大门票之外另购10元</td></tr><tr><td style="text-align:left;"><strong>藏品数量</strong></td><td style="text-align:left;">200余件中外钟表</td></tr><tr><td style="text-align:left;"><strong>产地</strong></td><td style="text-align:left;">英国、法国、瑞士、日本、清宫造办处、广州、苏州</td></tr><tr><td style="text-align:left;"><strong>年代跨度</strong></td><td style="text-align:left;">18世纪至20世纪初</td></tr><tr><td style="text-align:left;"><strong>奉先殿规制</strong></td><td style="text-align:left;">前殿九间、后殿九间，明代始建，清代重建</td></tr></tbody></table><p>奉先殿始建于明初，是皇帝&quot;家事&quot;级别的祖庙——太庙祭祀列朝先帝，奉先殿则更近&quot;家祭&quot;，逢年过节皇帝在此向列祖列宗行礼。殿宇前殿九间、后殿九间，黄琉璃瓦重檐顶，规制在内廷祭祀建筑中最为尊崇。展陈利用前后两殿及东西配殿，钟表依产地、年代和功能分区摆放。</p><p>馆藏钟表的精彩之处在于<strong>机械表演功能</strong>：许多钟表不仅是计时器，整点时刻还会触发机关——鸟鸣、乐奏、水法转动、人偶写字、花束绽放。这些&quot;自动机&quot;（automata）是18世纪欧洲机械工艺的炫技之作，也是当年打动乾隆帝、让它们得以进入紫禁城的关键卖点。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="写字人钟-机械人偶提笔写-八方向化-九土来王" tabindex="-1">写字人钟：机械人偶提笔写&quot;八方向化，九土来王&quot; <a class="header-anchor" href="#写字人钟-机械人偶提笔写-八方向化-九土来王" aria-label="Permalink to &quot;写字人钟：机械人偶提笔写&quot;八方向化，九土来王&quot;&quot;">​</a></h3><p>钟表馆最负盛名的藏品之一是英国制造的<strong>铜镀金写字人钟</strong>。这座钟的顶部设有一个机械人偶，上弦启动后，人偶会缓缓提笔，在纸上书写&quot;八方向化，九土来王&quot;八个汉字——笔迹流畅、提按有致，宛如真人挥毫。这并非魔术，而是18世纪欧洲自动机械的巅峰：人偶手臂内藏精密凸轮组，凸轮的轮廓控制笔尖的每一个运动轨迹，预先&quot;编程&quot;出完整的书写动作。此钟为英国钟表匠威廉森（Williamson）约于18世纪末制作，经广州口岸进入清宫，乾隆帝见之大喜，收入内廷。一座钟，就是一部用黄铜写成的&quot;程序&quot;——比计算机早了两个世纪。</p><h3 id="乾隆-中国最大的钟表收藏家" tabindex="-1">乾隆：中国最大的钟表收藏家 <a class="header-anchor" href="#乾隆-中国最大的钟表收藏家" aria-label="Permalink to &quot;乾隆：中国最大的钟表收藏家&quot;">​</a></h3><p>清代宫廷钟表收藏的爆发，与乾隆帝个人的痴迷密不可分。乾隆朝是西洋钟表输入中国的高峰期，英国、法国、瑞士的钟表商深知中国皇帝的口味，专门制作融合中国审美的&quot;中国市场钟&quot;：亭台楼阁式样、珐琅彩绘龙凤、配以水法与音乐。乾隆帝来者不拒，又命清宫造办处<strong>做钟处</strong>仿制——于是出现了&quot;乾隆花园式钟&quot;等中西合璧的御制精品。清宫鼎盛时期收藏钟表逾千件，奉先殿今日所陈，不过是当年内廷钟表收藏的十分之一二。一位皇帝的癖好，意外保存了世界钟表史上最完整的一批18世纪自动机械遗存。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>写字人钟（英国）</strong>：机械人偶提笔书写汉字，18世纪自动机械的巅峰演示，钟表馆的&quot;头号明星&quot;。</li><li><strong>铜镀金四象转花水法人打钟</strong>：四头大象牵引、水法旋转、人偶敲钟，集机械、雕塑、水景于一体，是欧洲&quot;音乐钟&quot;的典型。</li><li><strong>乾隆花园式钟（清宫造办处）</strong>：中西合璧的御制钟，亭台楼阁造型、珐琅彩绘，是宫廷自制钟的代表。</li><li><strong>嵌料石楼阁式钟</strong>：通体镶嵌各色料石（玻璃宝石），楼阁层叠，是&quot;中国市场钟&quot;的华丽典范。</li><li><strong>奉先殿建筑本身</strong>：明清帝后家庙的原构，九间重檐的祖庙规制值得在观钟之余抬头一看。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>留意表演时间</strong>：部分机械钟每天定时启动表演（如整点前后），进馆时可询问工作人员当日演示安排，错过写字人钟的动态演示会遗憾。</li><li><strong>从&quot;动&quot;处看起</strong>：优先寻找带水法、人偶、鸟鸣等自动表演功能的钟表，静态表盘难以体现这些藏品真正的价值。</li><li><strong>与珍宝馆联游</strong>：钟表馆（奉先殿）与珍宝馆（宁寿宫区）同在故宫东部，相距不远，建议一次游完两馆。</li><li><strong>预留40-60分钟</strong>：展品密集且细节丰富，匆匆走过只能看个热闹；细看机械结构与珐琅装饰需要时间。</li><li><strong>光线较暗</strong>：殿内展厅光线偏暗以保护文物，拍照需关闭闪光灯（馆内也禁止闪光灯）。</li></ul><hr><p><strong>📍 位置</strong>：故宫东侧奉先殿（东六宫以南） <strong>⏱️ 建议游览</strong>：40-60分钟 <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/zhenbao-guan.html">珍宝馆（宁寿宫区）</a><strong>🔗 周边</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/jiulong-bi.html">九龙壁</a>（宁寿宫区皇极门外） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',22)])])}const c=o(n,[["render",l]]);export{q as __pageData,c as default};
